478	    const base = window.location.origin + window.location.pathname;
479	    const p = new URLSearchParams({
480	      m: String(dimScores.m),
481	      i: String(dimScores.i),
482	      n: String(dimScores.n),
483	      d: String(dimScores.d),
484	    });
485	    return base + '?' + p.toString() + '#zone-zero';
486	  }
487	
488	  function buildShareText(): string {
489	    const score = calcScore(dimScores);
490	    const stateName = nameEl.textContent?.trim() || '';
491	    const constraint = (['m', 'i', 'n', 'd'] as const)
492	      .slice()
493	      .sort((a, b) => dimScores[a] - dimScores[b])[0];
494	    const cName = NAMES[constraint];
495	    const lines = [
496	      `My pilot city MIND score: ${score}/100 \u2014 ${stateName}`,
497	      `M=${dimScores.m} \u00B7 I=${dimScores.i} \u00B7 N=${dimScores.n} \u00B7 D=${dimScores.d}`,
498	      `Binding constraint: ${cName} Capital`,
499	      `Try the Zone Zero simulator \u2192`,
500	    ];
501	    return lines.join('\n');
502	  }
503	
504	  // -- OG meta updater --
505	  function buildOGImageURL(m: number, i: number, n: number, d: number): string {
506	    // Microlink screenshot API
507	    const ogRenderURL =
508	      'https://intelligenteconomics.ai/og-render.html' +
509	      '?m=' + m + '&i=' + i + '&n=' + n + '&d=' + d;
510	    return (
511	      'https://api.microlink.io/?' +
512	      'url=' + encodeURIComponent(ogRenderURL) +
513	      '&screenshot=true' +
514	      '&meta=false' +
515	      '&embed=screenshot.url' +
516	      '&waitForSelector=' + encodeURIComponent('[data-ready="true"]') +
517	      '&viewport.width=1200' +
518	      '&viewport.height=630'
519	    );
520	  }
521	
522	  function updateOGMeta(m: number, i: number, n: number, d: number): void {
523	    const score = calcScore({ m, i, n, d });
524	    const stateInfo = (() => {
525	      if (score >= 70) return { name: 'Symbiotic Zone', badge: 'THRIVING' };
526	      if (score >= 50) return { name: 'Healthy System', badge: 'THRIVING' };
527	      if (score >= 35) return { name: 'Under Stress', badge: 'STRESSED' };
528	      if (score >= 20) return { name: 'Critical Threshold', badge: 'CRITICAL' };
529	      if (score >= 1) return { name: 'Pre-Collapse', badge: 'CRITICAL' };
530	      return { name: 'Systemic Collapse', badge: 'COLLAPSED' };
531	    })();
532	    const title = `Zone Zero ${score}/100 \u2014 ${stateInfo.name} | Intelligent Economics`;
533	    const desc = `M=${m} \u00B7 I=${i} \u00B7 N=${n} \u00B7 D=${d} \u2014 ${stateInfo.badge}. Can you configure a Symbiotic Zone? Try the simulator.`;
534	    const imgURL = buildOGImageURL(m, i, n, d);
535	
536	    // Update <meta> tags that social crawlers read
537	    const setMeta = (sel: string, attr: string, val: string): void => {
538	      const el = document.querySelector(sel);
539	      if (el) el.setAttribute(attr, val);
540	    };
541	    setMeta('[property="og:title"]', 'content', title);
542	    setMeta('[property="og:description"]', 'content', desc);
543	    setMeta('[property="og:url"]', 'content', window.location.href);
544	    setMeta('[property="og:image"]', 'content', imgURL);
545	    setMeta('[name="twitter:title"]', 'content', title);
546	    setMeta('[name="twitter:description"]', 'content', desc);
547	    setMeta('[name="twitter:image"]', 'content', imgURL);
548	    document.title = title;
549	  }
550	
551	  // Copy link button
552	  const copyBtn = document.getElementById('zz-copy-btn');
553	  const copyLabel = document.getElementById('zz-copy-label');
554	  if (copyBtn && copyLabel) {
555	    copyBtn.addEventListener('click', async () => {
556	      trackEvent('Simulator Shared', { method: 'copy' });
557	      const url = buildShareURL();
558	      // Update browser URL + OG meta silently
559	      history.replaceState(
560	        null,
561	        '',
562	        '?' +
563	          new URLSearchParams({
564	            m: String(dimScores.m),
565	            i: String(dimScores.i),
566	            n: String(dimScores.n),
567	            d: String(dimScores.d),
568	          }).toString() +
569	          '#zone-zero',
570	      );
571	      updateOGMeta(dimScores.m, dimScores.i, dimScores.n, dimScores.d);
572	      try {
573	        await navigator.clipboard.writeText(url);
574	      } catch {
575	        // Fallback: select a temporary textarea
576	        const ta = document.createElement('textarea');
577	        ta.value = url;
578	        ta.style.position = 'fixed';
579	        ta.style.opacity = '0';
580	        document.body.appendChild(ta);
581	        ta.select();
582	        document.execCommand('copy');
583	        document.body.removeChild(ta);
584	      }
585	      copyBtn.classList.add('copy-ok');
586	      copyLabel.textContent = 'Copied!';
587	      setTimeout(() => {
588	        copyBtn.classList.remove('copy-ok');
589	        copyLabel.textContent = 'Copy link';
590	      }, 2200);
591	    });
592	  }
593	
594	  // Twitter / X share
595	  const twitterBtn = document.getElementById('zz-twitter-btn') as HTMLAnchorElement | null;
596	  function updateTwitterLink(): void {
597	    if (!twitterBtn) return;
598	    const text = buildShareText();
599	    const url = buildShareURL();
600	    twitterBtn.href =
601	      'https://twitter.com/intent/tweet?text=' + encodeURIComponent(text + '\n' + url);
602	  }
